49	class UsersScreen extends StatefulWidget {
50	  const UsersScreen({super.key});
51	
52	  @override
53	  State<UsersScreen> createState() => _UsersScreenState();
54	}
55	
56	class _UsersScreenState extends State<UsersScreen> {
57	  static const String _baseUrl = 'http://10.0.2.2:8000';
58	
59	  final List<UserCard> _users = [];
60	  final ScrollController _scrollController = ScrollController();
61	  final Set<int> _likedIds = {};
62	  final Set<int> _blockedIds = {};
63	
64	  int _page = 1;
65	  static const int _perPage = 30;
66	  bool _isLoading = false;
67	  bool _hasMore = true;
68	  String? _token;
69	  String? _errorMessage;
70	
71	  @override
72	  void initState() {
73	    super.initState();
74	    _init();
75	    _scrollController.addListener(_onScroll);
76	  }
77	
78	  @override
79	  void dispose() {
80	    _scrollController.dispose();
81	    super.dispose();
82	  }
83	
84	  Future<void> _init() async {
85	    _token = await ApiService.getToken();
86	    await _loadUsers();
87	  }
88	
89	  void _onScroll() {
90	    if (_scrollController.position.pixels >=
91	        _scrollController.position.maxScrollExtent - 200) {
92	      if (!_isLoading && _hasMore) {
93	        _loadUsers();
94	      }
95	    }
96	  }
97	
98	  Future<void> _loadUsers() async {
99	    if (_isLoading || !_hasMore) return;
100	    setState(() {
101	      _isLoading = true;
102	      _errorMessage = null;
103	    });
104	
105	    try {
106	      final headers = <String, String>{
107	        'Content-Type': 'application/json',
108	      };
109	      if (_token != null) {
110	        headers['Authorization'] = 'Bearer $_token';
111	      }
112	
113	      final uri = Uri.parse(
114	          '$_baseUrl/api/users?page=$_page&per_page=$_perPage');
115	      final response = await http.get(uri, headers: headers);
116	
117	      if (response.statusCode == 200) {
118	        final data = jsonDecode(response.body) as Map<String, dynamic>;
119	        final List<dynamic> rawUsers = data['users'] as List<dynamic>;
120	        final newUsers =
121	            rawUsers.map((u) => UserCard.fromJson(u as Map<String, dynamic>)).toList();
122	        setState(() {
123	          _users.addAll(newUsers);
124	          _hasMore = data['has_more'] as bool;
125	          _page++;
126	          _isLoading = false;
127	        });
128	      } else {
129	        setState(() {
130	          _errorMessage = 'Error ${response.statusCode}: ${response.body}';
131	          _isLoading = false;
132	        });
133	      }
134	    } catch (e) {
135	      setState(() {
136	        _errorMessage = 'Network error: $e';
137	        _isLoading = false;
138	      });
139	    }
140	  }
141	
142	  // ── Fetch current who-i-like list ─────────────────────────────────────────
143	
144	  Future<List<_RankItem>> _fetchWhoILike() async {
145	    try {
146	      final resp = await http.get(
147	        Uri.parse('$_baseUrl/api/who_i_like'),
148	        headers: {
149	          'Content-Type': 'application/json',
150	          if (_token != null) 'Authorization': 'Bearer $_token',
151	        },
152	      );
153	      if (resp.statusCode == 200) {
154	        final data = jsonDecode(resp.body) as Map<String, dynamic>;
155	        final users = (data['users'] as List<dynamic>).cast<Map<String, dynamic>>();
156	        return users.map((u) => _RankItem(
157	          id: u['id'] as int,
158	          username: u['username'] as String,
159	          age: u['age'] as int?,
160	          sex: u['sex'] as String?,
161	        )).toList();
162	      }
163	    } catch (_) {}
164	    return [];
165	  }
166	
167	  // ── Save re-ranking ───────────────────────────────────────────────────────
168	
169	  Future<void> _saveRerank(List<_RankItem> ranked) async {
170	    try {
171	      final rankings = ranked.asMap().entries.map((e) {
172	        return {'username': e.value.username, 'rank': e.key + 1};
173	      }).toList();
174	      await http.put(
175	        Uri.parse('$_baseUrl/api/like/rerank'),
176	        headers: {
177	          'Content-Type': 'application/json',
178	          if (_token != null) 'Authorization': 'Bearer $_token',
179	        },
180	        body: jsonEncode({'rankings': rankings}),
181	      );
182	    } catch (_) {}
183	  }
184	
185	  // ── Show ranking bottom sheet ─────────────────────────────────────────────
186	
187	  Future<void> _showRankingSheet(UserCard newUser, List<_RankItem> currentLikes) async {
188	    // Build initial list: existing likes + newly liked person at bottom
189	    final items = [
190	      ...currentLikes,
191	      _RankItem(
192	        id: newUser.id,
193	        username: newUser.username,
194	        age: newUser.age,
195	        sex: newUser.sex,
196	      ),
197	    ];
198	
199	    final saved = await showModalBottomSheet<bool>(
200	      context: context,
201	      isScrollControlled: true,
202	      backgroundColor: const Color(0xFF12121C),
203	      shape: const RoundedRectangleBorder(
204	        borderRadius: BorderRadius.vertical(top: Radius.circular(20)),
205	      ),
206	      builder: (ctx) => _RankingSheet(
207	        items: items,
208	        newUserId: newUser.id,
209	        baseUrl: _baseUrl,
210	        token: _token,
211	        onSave: (reordered) async {
212	          await _saveRerank(reordered);
213	          Navigator.of(ctx).pop(true);
214	        },
215	      ),
216	    );
217	
218	    if (saved == true) {
219	      // Remove the liked card from the grid
220	      setState(() {
221	        _likedIds.add(newUser.id);
222	        _users.removeWhere((u) => u.id == newUser.id);
223	      });
224	    }
225	  }
226	
227	  // ── Like / unlike ─────────────────────────────────────────────────────────
228	
229	  Future<void> _likeUser(UserCard user) async {
230	    if (_likedIds.contains(user.id)) {
231	      // Unlike
232	      try {
233	        await http.delete(
234	          Uri.parse('$_baseUrl/api/like/${user.id}'),
235	          headers: {
236	            'Content-Type': 'application/json',
237	            if (_token != null) 'Authorization': 'Bearer $_token',
238	          },
239	        );
240	        setState(() => _likedIds.remove(user.id));
241	      } catch (_) {}
242	      return;
243	    }
244	
245	    // Like → POST first
246	    try {
247	      final resp = await http.post(
248	        Uri.parse('$_baseUrl/api/like'),
249	        headers: {
250	          'Content-Type': 'application/json',
251	          if (_token != null) 'Authorization': 'Bearer $_token',
252	        },
253	        body: jsonEncode({'liked_user_id': user.id}),
254	      );
255	      if (resp.statusCode == 201 || resp.statusCode == 200) {
256	        // Fetch current like list (excluding the newly liked user, who was
257	        // just added by the POST, so they may already be in the list).
258	        final currentLikes = await _fetchWhoILike();
259	        // Remove the new user from the middle of the list if backend already
260	        // appended them — we'll put them at the bottom ourselves.
261	        final withoutNew = currentLikes.where((u) => u.id != user.id).toList();
262	
263	        if (!mounted) return;
264	        await _showRankingSheet(user, withoutNew);
265	      }
266	    } catch (e) {
267	      if (mounted) {
268	        ScaffoldMessenger.of(context).showSnackBar(
269	          SnackBar(content: Text('Like failed: $e')),
270	        );
271	      }
272	    }
273	  }
274	
275	  Future<void> _blockUser(int userId) async {
276	    try {
277	      final resp = await http.post(
278	        Uri.parse('$_baseUrl/api/block'),
279	        headers: {
280	          'Content-Type': 'application/json',
281	          if (_token != null) 'Authorization': 'Bearer $_token',
282	        },
283	        body: jsonEncode({'blocked_user_id': userId}),
284	      );
285	      if (resp.statusCode == 201 || resp.statusCode == 200) {
286	        setState(() {
287	          _blockedIds.add(userId);
288	          _users.removeWhere((u) => u.id == userId);
289	        });
290	      }
291	    } catch (_) {}
292	  }
293	
294	  Future<void> _refresh() async {
295	    setState(() {
296	      _users.clear();
297	      _page = 1;
298	      _hasMore = true;
299	      _errorMessage = null;
300	    });
301	    await _loadUsers();
302	  }
